parameters.jsCode:
const { scenarios, filter, ci_metadata } = $input.first().json;

let filtered = scenarios;

// Filter by agent_id
if (filter.agent_id) {
  filtered = filtered.filter(s => s.agent_id === filter.agent_id);
}

// Filter by priority (include all at or above specified level)
if (filter.priority) {
  const priorities = ['critical', 'high', 'medium', 'low'];
  const minIndex = priorities.indexOf(filter.priority);
  filtered = filtered.filter(s => 
    priorities.indexOf(s.priority) <= minIndex
  );
}

// Filter by category
if (filter.category) {
  filtered = filtered.filter(s => s.category === filter.category);
}

// Filter by specific scenario IDs
if (filter.scenario_ids?.length > 0) {
  filtered = filtered.filter(s => 
    filter.scenario_ids.includes(s.id)
  );
}

// Sort by priority (critical first)
const priorityOrder = { critical: 0, high: 1, medium: 2, low: 3 };
filtered.sort((a, b) => priorityOrder[a.priority] - priorityOrder[b.priority]);

// Add execution metadata
const executionPlan = filtered.map((scenario, index) => ({
  ...scenario,
  execution_index: index,
  total_scenarios: filtered.length,
  ci_metadata
}));

return executionPlan.map(s => ({ json: s }));

