const scenario = $('Loop Through Scenarios').item.json;
const response = $input.first().json;

// Handle API error
if (response.error || !response.body) {
  return {
    json: {
      scenario_id: scenario.id,
      scenario_name: scenario.name,
      scenario_category: scenario.category,
      scenario_priority: scenario.priority,
      agent_id: scenario.agent_id,
      status: 'error',
      error: response.error?.message || 'No response body',
      overall_passed: false,
      ci_metadata: scenario.ci_metadata,
      timestamp: new Date().toISOString()
    }
  };
}

const result = response.body;

// Extract tool calls from transcript
const toolCalls = [];
const transcriptTurns = [];

if (result.transcript) {
  for (const turn of result.transcript) {
    transcriptTurns.push({
      role: turn.role,
      message: turn.message?.substring(0, 200)
    });

    if (turn.tool_calls) {
      for (const call of turn.tool_calls) {
        toolCalls.push({
          name: call.tool_name || call.name,
          arguments: call.arguments
        });
      }
    }
  }
}

// Validate expected tool calls
const expectedTools = scenario.expected_tool_calls || [];
const actualToolNames = toolCalls.map(tc => tc.name);
const missingTools = expectedTools.filter(t => !actualToolNames.includes(t));

const toolValidation = {
  passed: missingTools.length === 0,
  expected: expectedTools,
  actual: actualToolNames,
  missing: missingTools
};

// Parse evaluation criteria results
const evaluations = {};
let allCriteriaPassed = true;

if (result.evaluation?.criteria_results) {
  for (const [id, data] of Object.entries(result.evaluation.criteria_results)) {
    const passed = data.passed || data.result === 'passed' || data.result === true;
    evaluations[id] = {
      name: data.name || id,
      passed,
      reasoning: data.reasoning || data.explanation || 'No reasoning provided'
    };
    if (!passed) allCriteriaPassed = false;
  }
}

// Overall pass/fail
const overallPassed = toolValidation.passed && allCriteriaPassed;

return {
  json: {
    scenario_id: scenario.id,
    scenario_name: scenario.name,
    scenario_category: scenario.category,
    scenario_priority: scenario.priority,
    agent_id: scenario.agent_id,
    status: 'completed',
    overall_passed: overallPassed,
    tool_validation: toolValidation,
    evaluation_results: evaluations,
    metrics: {
      turn_count: transcriptTurns.length,
      tool_call_count: toolCalls.length
    },
    ci_metadata: scenario.ci_metadata,
    timestamp: new Date().toISOString()
  }
};

const results = $input.first().json.test_results;

// Basic counts
const total = results.length;
const passed = results.filter(r => r.overall_passed).length;
const failed = results.filter(r => !r.overall_passed).length;
const errored = results.filter(r => r.status === 'error').length;

// By priority
const byPriority = {};
for (const pri of ['critical', 'high', 'medium', 'low']) {
  const priResults = results.filter(r => r.scenario_priority === pri);
  if (priResults.length > 0) {
    byPriority[pri] = {
      total: priResults.length,
      passed: priResults.filter(r => r.overall_passed).length,
      success_rate: Math.round(priResults.filter(r => r.overall_passed).length / priResults.length * 100)
    };
  }
}

// Critical failures
const criticalFailures = results.filter(r => 
  !r.overall_passed && r.scenario_priority === 'critical'
);

// Tool failures
const toolFailures = results.filter(r => 
  r.tool_validation && !r.tool_validation.passed
);

// CI metadata from first result
const ciMetadata = results[0]?.ci_metadata || {};

return {
  json: {
    summary: {
      total,
      passed,
      failed,
      errored,
      success_rate: Math.round(passed / total * 100),
      tool_call_accuracy: toolFailures.length === 0 ? 100 : Math.round((total - toolFailures.length) / total * 100)
    },
    by_priority: byPriority,
    critical_failures: criticalFailures.map(r => ({
      scenario: r.scenario_name,
      agent: r.agent_id
    })),
    tool_failures: toolFailures.map(r => ({
      scenario: r.scenario_name,
      missing: r.tool_validation.missing
    })),
    ci_metadata: ciMetadata,
    detailed_results: results,
    timestamp: new Date().toISOString()
  }
};

const data = $input.first().json;
const { summary, by_priority, critical_failures, tool_failures, detailed_results } = data;

let report = `# Voice Agent Test Report\n\n`;
report += `**Generated:** ${new Date().toISOString()}\n\n`;

// Summary
report += `## Summary\n\n`;
report += `| Metric | Value |\n`;
report += `|--------|-------|\n`;
report += `| Total Tests | ${summary.total} |\n`;
report += `| Passed | ${summary.passed} |\n`;
report += `| Failed | ${summary.failed} |\n`;
report += `| **Success Rate** | **${summary.success_rate}%** |\n`;
report += `| Tool Accuracy | ${summary.tool_call_accuracy}% |\n\n`;

// Status badge
if (summary.success_rate >= 95) {
  report += `**Status: HEALTHY**\n\n`;
} else if (summary.success_rate >= 80) {
  report += `**Status: WARNING**\n\n`;
} else {
  report += `**Status: CRITICAL**\n\n`;
}

// Critical failures
if (critical_failures.length > 0) {
  report += `## Critical Failures\n\n`;
  for (const cf of critical_failures) {
    report += `- **${cf.scenario}** (${cf.agent})\n`;
  }
  report += `\n`;
}

// Tool failures
if (tool_failures.length > 0) {
  report += `## Tool Validation Failures\n\n`;
  for (const tf of tool_failures) {
    report += `- **${tf.scenario}**: Missing \`${tf.missing.join(', ')}\`\n`;
  }
  report += `\n`;
}

// Results by priority
report += `## Results by Priority\n\n`;
report += `| Priority | Total | Passed | Rate |\n`;
report += `|----------|-------|--------|------|\n`;
for (const [pri, stats] of Object.entries(by_priority)) {
  report += `| ${pri} | ${stats.total} | ${stats.passed} | ${stats.success_rate}% |\n`;
}
report += `\n`;

// Detailed results
report += `## Detailed Results\n\n`;
for (const result of detailed_results) {
  const icon = result.overall_passed ? 'PASS' : 'FAIL';
  report += `### [${icon}] ${result.scenario_name}\n`;
  report += `- Category: ${result.scenario_category} | Priority: ${result.scenario_priority}\n`;

  if (!result.tool_validation?.passed) {
    report += `- Tool Validation: FAILED - Missing: ${result.tool_validation.missing.join(', ')}\n`;
  }

  for (const [id, ev] of Object.entries(result.evaluation_results || {})) {
    const evIcon = ev.passed ? 'PASS' : 'FAIL';
    report += `- [${evIcon}] ${ev.name}: ${ev.reasoning.substring(0, 100)}\n`;
  }
  report += `\n`;
}

return {
  json: {
    report_markdown: report,
    summary: data.summary,
    critical_failures: data.critical_failures,
    ci_metadata: data.ci_metadata,
    has_failures: summary.failed > 0,
    has_critical_failures: critical_failures.length > 0,
    timestamp: new Date().toISOString()
  }
};
